#!/usr/bin/env node
/**
 * Prebuild script: fetch products from admin API and save as generated data.
 *
 * Uses native fetch (Node 24+) with cache fallback: if the API is
 * unreachable, reuses the previously written generated file so deploys
 * keep working through transient outages. Fails loudly (exit 1) only on
 * the first build when no cache exists.
 */
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";
import { fetchJsonWithFallback } from "./lib/fetch-with-fallback.mjs";
import { rawProductsResponseSchema } from "./schemas.mjs";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ADMIN_API = process.env.ADMIN_API_URL || "https://admin.rimhappywoods.top";
const API_URL = `${ADMIN_API}/api/products`;
const OUT_DIR = path.resolve(__dirname, "..", "src/data/generated");
const PRODUCTS_CACHE = path.resolve(OUT_DIR, "products-raw.json"); // raw API response for fallback
const PRODUCTS_JSON = path.resolve(OUT_DIR, "products.json");     // mapped output
const CATEGORIES_JSON = path.resolve(OUT_DIR, "categories.json");
const PRODUCTS_TS = path.resolve(OUT_DIR, "products-data.ts");
async function main() {
  console.log("📦 Fetching products from admin API...");
  console.log(`   ${API_URL}`);

  const products = await fetchJsonWithFallback(API_URL, {
    cachePath: PRODUCTS_CACHE,
    label: "products",
  });

  try {
    rawProductsResponseSchema.parse(products);
  } catch (err) {
    const summary = err.issues
      .map((i) => i.path.join(".") + ": " + i.message)
      .join("; ");
    console.error(`❌ Products API response failed validation: ${summary}. Build aborted to prevent shipping malformed data.`);
    process.exit(1);
  }

  const mapped = products
    .map((p) => {
      let image;
      if (p.image_key) {
        image = "/images/" + p.image_key;
      }
      return {
        id: p.id,
        title: p.title,
        description: p.description || undefined,
        image,
        badge: p.badge || undefined,
        badgeColor: p.badge_color || undefined,
        category: p.category_name || undefined,
        series: p.series_name || undefined,
      };
    })
    .filter((p) => p.image);

  const cats = ["All", ...new Set(mapped.map((p) => p.category).filter(Boolean))];

  fs.mkdirSync(OUT_DIR, { recursive: true });
  fs.writeFileSync(PRODUCTS_JSON, JSON.stringify(mapped, null, 2));
  fs.writeFileSync(CATEGORIES_JSON, JSON.stringify(cats, null, 2));

  const tsContent = `// Auto-generated by scripts/fetch-products.mjs — DO NOT EDIT
import type { ProductCardData } from "@/types";

export const generatedProducts: (ProductCardData & { series?: string })[] = ${JSON.stringify(mapped, null, 2)};

export const generatedCategories: string[] = ${JSON.stringify(cats, null, 2)};
`;
  fs.writeFileSync(PRODUCTS_TS, tsContent);

  console.log(`✅ ${mapped.length} products saved to src/data/generated/`);
}

main().catch((err) => {
  console.error("❌ Failed to fetch products:", err.message);
  console.error("   No cached fallback available. Build cannot proceed safely.");
  process.exit(1);
});
